window.__PAGE_RUNTIME_PARTIALS__["partials/guia-05-herramientas-content.html"] = "<button class=\"hamburger\" onclick=\"toggleSidebar()\" aria-label=\"Menú\">&#9776;</button>\r\n<button class=\"btn-sb-expand\" onclick=\"showSidebar()\" title=\"Mostrar barra lateral\">&#9776;</button>\r\n\r\n<div class=\"layout app-layout\">\r\n  <nav class=\"sidebar\" id=\"sidebar\">\r\n    <div class=\"sidebar-logo\">\r\n      <div class=\"badge\">SENA · FPI</div>\r\n      <h2>Guia 5 - Operar Herramientas Informaticas y Digitales</h2>\r\n      <p>Sistemas Teleinformaticos</p>\r\n      <button class=\"btn-sb-collapse\" onclick=\"hideSidebar()\" title=\"Ocultar barra lateral\">&#9664;</button>\r\n    </div>\r\n\r\n    <div class=\"sidebar-ficha\" id=\"sb-ficha-ok\" style=\"display:none\">\r\n      <div class=\"sf-label\">Tu grupo</div>\r\n      <div class=\"sf-inst\" id=\"sb-inst\"></div>\r\n      <div class=\"sf-meta\" id=\"sb-grupo-meta\"></div>\r\n      <div class=\"sf-badge\" id=\"sb-badge\"></div>\r\n    </div>\r\n    <div class=\"sidebar-noficha\" id=\"sb-ficha-warn\">\r\n      <a href=\"index.html\">Inicio | Seleccionar grupo / ficha</a>\r\n    </div>\r\n\r\n    <div class=\"progress-wrap\">\r\n      <div class=\"progress-label\">\r\n        <span>Progreso</span>\r\n        <span id=\"progressValue\">0%</span>\r\n      </div>\r\n      <div class=\"progress-bar-bg\">\r\n        <div class=\"progress-bar\" id=\"progressBar\"></div>\r\n      </div>\r\n      <p class=\"progress-note\">El avance se guarda localmente en este navegador.</p>\r\n      <button type=\"button\" class=\"reset-button\" id=\"resetProgress\">Reiniciar respuestas</button>\r\n    </div>\r\n\r\n    <div class=\"nav-section\">\r\n      <div class=\"nav-label\">Informaci&oacute;n</div>\r\n      <a class=\"nav-link active\" href=\"#identificacion\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128203;</span> Identificaci&oacute;n\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#presentacion\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128075;</span> Presentaci&oacute;n\r\n      </a>\r\n    </div>\r\n\r\n    <div class=\"nav-section\">\r\n      <div class=\"nav-label\">Actividades</div>\r\n      <a class=\"nav-link\" href=\"#reflexion\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128172;</span> 3.1 Reflexi&oacute;n Inicial\r\n        <span class=\"check\">&#10003;</span>\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#contexto\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128269;</span> 3.2 Contextualizaci&oacute;n\r\n        <span class=\"check\">&#10003;</span>\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#apropiacion\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128218;</span> 3.3 Apropiaci&oacute;n\r\n        <span class=\"check\">&#10003;</span>\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#transferencia\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128640;</span> 3.4 Transferencia\r\n        <span class=\"check\">&#10003;</span>\r\n      </a>\r\n    </div>\r\n\r\n    <div class=\"nav-section\">\r\n      <div class=\"nav-label\">Recursos</div>\r\n      <a class=\"nav-link\" href=\"#evidencias\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128202;</span> Evidencias\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#glosario\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128214;</span> Glosario\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#referencias\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128279;</span> Referencias\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#material-apoyo\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128194;</span> Material de Apoyo\r\n      </a>\r\n    </div>\r\n\r\n    <div class=\"nav-section\">\r\n      <div class=\"nav-label\">Guia asignada</div>\r\n      <a class=\"nav-guide current\" id=\"currentGuideNavLink\" href=\"grupo-11a-guia-05-herramientas-informaticas-digitales.html\" data-current-file=\"grupo-11a-guia-05-herramientas-informaticas-digitales.html\">\r\n        <span class=\"g-icon\">&#128215;</span>\r\n        <span class=\"g-info\">\r\n          <span class=\"g-num\">Guia 5</span>\r\n          <span class=\"g-name\" id=\"currentGuideNavLabel\">Operar herramientas informaticas y digitales | 11A</span>\r\n        </span>\r\n        <span class=\"g-tag actual\">Actual</span>\r\n      </a>\r\n    </div>\r\n\r\n    <a class=\"nav-home-link\" href=\"calendario-academico-2026.html\">&#128197; <span>Calendario 2026</span></a>\r\n    <a class=\"nav-home-link\" href=\"index.html\">&#127968; <span>Volver al Inicio</span></a>\r\n  </nav>\r\n\r\n  <main class=\"main app-main\">\r\n    <div class=\"topbar\">\r\n      <div class=\"topbar-title\">\r\n        <strong>Guia 5 - Operar Herramientas Informaticas y Digitales</strong>\r\n      </div>\r\n      <div class=\"topbar-meta\">\r\n        <span class=\"meta-item\"><span>&#9201;</span><span>48 horas</span></span>\r\n        <span class=\"meta-item\"><span>&#128197;</span><span>2026</span></span>\r\n        <span class=\"meta-item\"><span>&#127979;</span><span id=\"topbarCampus\">Santa Barbara | 11A</span></span>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <div class=\"hero\" id=\"inicio\">\r\n        <div class=\"tag\">Guia 5 | Fase: Evaluacion</div>\r\n        <h1>Operar herramientas informaticas y digitales</h1>\r\n        <p>\r\n          En esta guia reconocerás herramientas digitales, clasificarás archivos,\r\n          compararás sistemas operativos y documentarás procedimientos tecnicos\r\n          en entornos controlados.\r\n        </p>\r\n        <div class=\"hero-meta\">\r\n          <div class=\"hero-meta-item\">&#127963; SENA &mdash; Servicio Nacional de Aprendizaje</div>\r\n          <div class=\"hero-meta-item\">&#128205; Competencia: Operar herramientas informaticas y digitales</div>\r\n          <div class=\"hero-meta-item\">&#9201; 48 horas</div>\r\n          <div class=\"hero-meta-item\">&#127891; C&oacute;digo: 233108 &middot; V1</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"identificacion\" class=\"section-title\">Identificaci&oacute;n de la Gu&iacute;a</div>\r\n      <div class=\"card open\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\" style=\"background:#e8f5e9\">&#128203;</div>\r\n            <div>\r\n              <h3>Datos del Programa de Formaci&oacute;n</h3>\r\n              <p>Informaci&oacute;n oficial del programa y la competencia</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"table-scroll\">\r\n            <table class=\"data-table ident-table\">\r\n              <tbody>\r\n                <tr><td>Denominaci&oacute;n del Programa</td><td>Sistemas Teleinform&aacute;ticos</td></tr>\r\n                <tr><td>C&oacute;digo del Programa</td><td>233108 &middot; Versi&oacute;n 1</td></tr>\r\n                <tr><td>Nombre del Proyecto Formativo</td><td>Fortalecimiento de los servicios Teleinform&aacute;ticos de equipos y redes en las MIPYMES de la regi&oacute;n.</td></tr>\r\n                <tr><td>Fase del Proyecto</td><td>Evaluaci&oacute;n</td></tr>\r\n                <tr><td>Actividad del Proyecto</td><td>Diagnosticar el estado de la infraestructura de redes, equipos inform&aacute;ticos y solicitudes de servicio t&eacute;cnico.</td></tr>\r\n                <tr><td>Competencia</td><td>Operar herramientas inform&aacute;ticas y digitales de acuerdo con protocolos y manuales t&eacute;cnicos.</td></tr>\r\n                <tr><td>Resultado de Aprendizaje</td><td>RAP 1 - Caracterizar herramientas inform&aacute;ticas seg&uacute;n el contexto tecnol&oacute;gico de la organizaci&oacute;n.</td></tr>\r\n                <tr><td>Duraci&oacute;n</td><td>48 Horas</td></tr>\r\n              </tbody>\r\n            </table>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"presentacion\" class=\"section-title\">Presentaci&oacute;n</div>\r\n      <div class=\"card open\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\" style=\"background:#e3f2fd\">&#128075;</div>\r\n            <div>\r\n              <h3>Bienvenida a la Gu&iacute;a</h3>\r\n              <p>Conoce el contexto y las metas de esta gu&iacute;a de herramientas digitales</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <p class=\"intro-text\">\r\n            Bienvenido, aprendiz, a la gu&iacute;a <strong>Operar herramientas inform&aacute;ticas y digitales</strong>.\r\n            En este recorrido fortalecer&aacute;s el uso de recursos digitales para documentar procesos,\r\n            clasificar informaci&oacute;n y resolver situaciones t&eacute;cnicas con criterio.\r\n          </p>\r\n          <p class=\"intro-text\">\r\n            Esta gu&iacute;a te acerca al reconocimiento de herramientas, extensiones de archivo,\r\n            sistemas operativos y procesos de instalaci&oacute;n en entornos controlados, siempre\r\n            promoviendo el orden, la seguridad y la correcta documentaci&oacute;n del trabajo realizado.\r\n          </p>\r\n          <p class=\"intro-text\">\r\n            Las actividades est&aacute;n articuladas al programa <strong>Sistemas Teleinform&aacute;ticos</strong>\r\n            y al proyecto formativo orientado al fortalecimiento de servicios teleinform&aacute;ticos\r\n            en equipos y redes para las MIPYMES de la regi&oacute;n.\r\n          </p>\r\n          <div class=\"info-box green\" style=\"margin-top:14px\">\r\n            <div class=\"label\">En esta gu&iacute;a desarrollar&aacute; actividades que le permitir&aacute;n:</div>\r\n            <ul>\r\n              <li>Reconocer conceptos b&aacute;sicos sobre restauraci&oacute;n, arranque y formateo.</li>\r\n              <li>Relacionar herramientas digitales con sus funciones y usos.</li>\r\n              <li>Clasificar extensiones de archivo y programas asociados.</li>\r\n              <li>Investigar requerimientos m&iacute;nimos de sistemas operativos.</li>\r\n              <li>Documentar procesos de instalaci&oacute;n y evidencias t&eacute;cnicas de manera organizada.</li>\r\n            </ul>\r\n          </div>\r\n          <div class=\"quote\">\r\n            \"Aprender a usar bien las herramientas digitales tambi&eacute;n es aprender a resolver problemas con orden, criterio y responsabilidad.\"\r\n            <cite>Gu&iacute;a 5 - Orientaci&oacute;n de trabajo</cite>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"reflexion\" class=\"section-title\">3.1 &middot; Actividades de Reflexi&oacute;n Inicial</div>\r\n      <div class=\"info-box blue\" style=\"margin-bottom:16px\">\r\n        <p>Antes de intervenir equipos o software, analice el caso, identifique s&iacute;ntomas y organice un procedimiento seguro de diagn&oacute;stico.</p>\r\n      </div>\r\n      <div class=\"card open cat-reflexion\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\">&#128172;</div>\r\n            <div>\r\n              <h3>Actividades de Reflexi&oacute;n Inicial</h3>\r\n              <p>1 actividad &middot; Duraci&oacute;n aproximada: 1 hora</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.1.1</span>\r\n              <span class=\"activity-title\">Caso de diagnostico: equipos sin arranque</span>\r\n              <span class=\"mission-chip\">Mision de arranque</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <div class=\"diagnostic-layout\">\r\n                <article class=\"case-card case-hero\">\r\n                  <div class=\"subsection-head\">\r\n                    <span class=\"case-label\">Situacion problema</span>\r\n                    <p>Analiza el escenario antes de empezar tu bitacora de diagnostico.</p>\r\n                  </div>\r\n                  <h3>Recepcion de equipos recien ensamblados</h3>\r\n                  <p>\r\n                    Se recibio un grupo de quince computadores nuevos para ser ensamblados.\r\n                    Despues del ensamble, al encenderlos aparece una advertencia de arranque\r\n                    y se debe verificar que componente o configuracion falta para lograr\r\n                    la operatividad total.\r\n                  </p>\r\n                  <div class=\"info-box blue\">\r\n                    <strong>Meta de la actividad</strong>\r\n                    <p>\r\n                      Identificar causas probables, organizar una revision segura y\r\n                      seleccionar herramientas digitales para documentar el caso.\r\n                    </p>\r\n                  </div>\r\n                  <div class=\"diagnosis-points\">\r\n                    <div class=\"diagnosis-point\">\r\n                      <strong>Observa</strong>\r\n                      <p>Reconoce que mensaje aparece y en que momento del arranque se presenta la falla.</p>\r\n                    </div>\r\n                    <div class=\"diagnosis-point\">\r\n                      <strong>Analiza</strong>\r\n                      <p>Relaciona sintomas, evidencias y causas posibles sin intervenir de forma apresurada.</p>\r\n                    </div>\r\n                    <div class=\"diagnosis-point\">\r\n                      <strong>Documenta</strong>\r\n                      <p>Registra una ruta de revision clara y las herramientas digitales con las que entregarias el caso.</p>\r\n                    </div>\r\n                  </div>\r\n                </article>\r\n\r\n                <aside class=\"support-column\">\r\n                  <div class=\"support-card\">\r\n                    <div class=\"subsection-head\">\r\n                      <strong>Evidencias visuales del caso</strong>\r\n                      <p>Usa estas pistas para orientar tu analisis tecnico.</p>\r\n                    </div>\r\n                    <div class=\"diagnosis-gallery\">\r\n                      <figure class=\"media-card\">\r\n                        <img\r\n                          src=\"assets/img/no-bootable-device.jpeg\"\r\n                          alt=\"Mensaje de no bootable device\"\r\n                        >\r\n                        <figcaption>No bootable device</figcaption>\r\n                      </figure>\r\n                      <figure class=\"media-card\">\r\n                        <img\r\n                          src=\"assets/img/operating-system-not-found.jpeg\"\r\n                          alt=\"Mensaje de operating system not found\"\r\n                        >\r\n                        <figcaption>Operating system not found</figcaption>\r\n                      </figure>\r\n                    </div>\r\n                  </div>\r\n\r\n                  <div class=\"checklist-card compact-card\">\r\n                    <h4>Senales que puedes registrar</h4>\r\n                    <ul class=\"mini-list\">\r\n                      <li>Mensaje exacto mostrado por BIOS o UEFI.</li>\r\n                      <li>Presencia o ausencia del disco en la configuracion de arranque.</li>\r\n                      <li>Cables, conexiones y respuesta general del equipo al encender.</li>\r\n                      <li>Acciones que deben evitarse hasta confirmar la causa del fallo.</li>\r\n                    </ul>\r\n                  </div>\r\n                </aside>\r\n              </div>\r\n\r\n              <div class=\"checklist-card compact-card\">\r\n                <div class=\"subsection-head\">\r\n                  <strong>Ruta sugerida de diagnostico</strong>\r\n                  <p>Ordena tu respuesta en cuatro momentos antes de diligenciar la bitacora.</p>\r\n                </div>\r\n                <div class=\"diagnostic-steps\">\r\n                  <article class=\"step-card\">\r\n                    <span class=\"step-number\">1</span>\r\n                    <strong>Lectura del caso</strong>\r\n                    <p>Comprende el contexto del ensamble y la falla reportada antes de proponer acciones.</p>\r\n                  </article>\r\n                  <article class=\"step-card\">\r\n                    <span class=\"step-number\">2</span>\r\n                    <strong>Registro de sintomas</strong>\r\n                    <p>Describe lo que ocurre al encender, el mensaje observado y las evidencias visibles.</p>\r\n                  </article>\r\n                  <article class=\"step-card\">\r\n                    <span class=\"step-number\">3</span>\r\n                    <strong>Analisis tecnico</strong>\r\n                    <p>Propone causas probables y define que accion no realizarias de inmediato.</p>\r\n                  </article>\r\n                  <article class=\"step-card\">\r\n                    <span class=\"step-number\">4</span>\r\n                    <strong>Plan y entrega</strong>\r\n                    <p>Organiza la revision por pasos y selecciona herramientas para documentar el caso.</p>\r\n                  </article>\r\n                </div>\r\n              </div>\r\n\r\n              <div class=\"panel-grid\">\r\n                <form class=\"work-form\" autocomplete=\"off\">\r\n                  <div class=\"form-intro\">\r\n                    <span>Bitacora de trabajo</span>\r\n                    <h3>Registra tu diagnostico inicial</h3>\r\n                    <p>\r\n                      Completa la actividad en tres momentos: observacion del caso,\r\n                      analisis del fallo y plan de revision segura.\r\n                    </p>\r\n                  </div>\r\n\r\n                  <div class=\"bitacora-stack\">\r\n                    <section class=\"bitacora-block\">\r\n                      <div class=\"subsection-head\">\r\n                        <strong>1. Observacion del caso</strong>\r\n                        <p>Describe sintomas, mensajes y evidencias tal como los identificas.</p>\r\n                      </div>\r\n                      <div class=\"form-grid\">\r\n                        <label>\r\n                          <span>Que pasa al encender</span>\r\n                          <textarea rows=\"4\" data-store=\"bitacora-sintomas\" data-track placeholder=\"Describe sintomas, comportamiento del equipo y momento en que ocurre la falla.\"></textarea>\r\n                        </label>\r\n                        <label>\r\n                          <span>Mensaje en pantalla</span>\r\n                          <textarea rows=\"4\" data-store=\"bitacora-mensaje\" data-track placeholder=\"Transcribe o resume el mensaje observado.\"></textarea>\r\n                        </label>\r\n                        <label>\r\n                          <span>Evidencias observadas</span>\r\n                          <textarea rows=\"4\" data-store=\"bitacora-evidencias\" data-track placeholder=\"Luces, pitidos, ventiladores, pantalla negra, cables, BIOS, etc.\"></textarea>\r\n                        </label>\r\n                      </div>\r\n                    </section>\r\n\r\n                    <section class=\"bitacora-block\">\r\n                      <div class=\"subsection-head\">\r\n                        <strong>2. Analisis del fallo</strong>\r\n                        <p>Explica que causas consideras viables y que accion evitarias de inmediato.</p>\r\n                      </div>\r\n                      <div class=\"form-grid\">\r\n                        <label>\r\n                          <span>Causas probables (minimo 3)</span>\r\n                          <textarea rows=\"4\" data-store=\"bitacora-causas\" data-track placeholder=\"Ejemplo: ausencia de disco booteable, orden de arranque incorrecto o sistema no instalado.\"></textarea>\r\n                        </label>\r\n                        <label>\r\n                          <span>Accion que no realizarias de inmediato y por que</span>\r\n                          <textarea rows=\"4\" data-store=\"bitacora-no-hacer\" data-track placeholder=\"Ejemplo: no formatear sin respaldo. Explica la razon.\"></textarea>\r\n                        </label>\r\n                      </div>\r\n                    </section>\r\n\r\n                    <section class=\"bitacora-block\">\r\n                      <div class=\"subsection-head\">\r\n                        <strong>3. Plan de revision y cierre</strong>\r\n                        <p>Organiza la secuencia de trabajo, las herramientas digitales y tu conclusion final.</p>\r\n                      </div>\r\n                      <div class=\"form-grid\">\r\n                        <label>\r\n                          <span>Plan de revision basico (minimo 5 pasos)</span>\r\n                          <textarea rows=\"5\" data-store=\"bitacora-plan\" data-track placeholder=\"Enumera acciones seguras y ordenadas para revisar el caso.\"></textarea>\r\n                        </label>\r\n                        <label>\r\n                          <span>Herramientas digitales para documentar y entregar</span>\r\n                          <textarea rows=\"5\" data-store=\"bitacora-herramientas\" data-track placeholder=\"Indica al menos 3 herramientas y justifica su uso.\"></textarea>\r\n                        </label>\r\n                        <label>\r\n                          <span>Conclusion breve</span>\r\n                          <textarea rows=\"4\" data-store=\"bitacora-conclusion\" data-track placeholder=\"Resume hallazgos, decisiones y cuidados tecnicos.\"></textarea>\r\n                        </label>\r\n                      </div>\r\n                    </section>\r\n                  </div>\r\n\r\n                  <div class=\"checklist-card compact-card\" style=\"margin-top:16px;\">\r\n                    <h3>Producto para entregar</h3>\r\n                    <p>La evidencia final debe quedar organizada y completa con los siguientes elementos:</p>\r\n                    <ul class=\"note-list\">\r\n                      <li>Registro del caso y contexto observado.</li>\r\n                      <li>Causas probables del fallo.</li>\r\n                      <li>Plan de revision por pasos.</li>\r\n                      <li>Herramientas digitales seleccionadas y su justificacion.</li>\r\n                      <li>Conclusion breve del analisis realizado.</li>\r\n                    </ul>\r\n                  </div>\r\n                </form>\r\n\r\n                <aside class=\"support-column\">\r\n                  <div class=\"checklist-card compact-card\">\r\n                    <h4>Criterios para una buena respuesta</h4>\r\n                    <ul class=\"mini-list\">\r\n                      <li>La descripcion del fallo debe coincidir con las evidencias visuales.</li>\r\n                      <li>Las causas probables deben ser tecnicamente coherentes con el mensaje de arranque.</li>\r\n                      <li>El plan de revision debe ir de lo mas seguro y basico a lo mas especifico.</li>\r\n                      <li>La herramienta digital elegida debe apoyar la documentacion y la entrega.</li>\r\n                    </ul>\r\n                  </div>\r\n                  <div class=\"support-card\">\r\n                    <img src=\"assets/img/producto-entregar.png\" alt=\"Resumen del producto a entregar\">\r\n                    <p>Usa esta pagina como borrador y luego organiza la entrega final con un archivo formal de bitacora o informe.</p>\r\n                  </div>\r\n                  <div class=\"support-card\">\r\n                    <img src=\"assets/img/socializacion.png\" alt=\"Indicaciones para socializacion\">\r\n                    <p>Durante la socializacion cada equipo debe exponer una causa probable, un paso del plan de revision y una herramienta digital seleccionada.</p>\r\n                  </div>\r\n                </aside>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"contexto\" class=\"section-title\">3.2 &middot; Contextualizaci&oacute;n e Identificaci&oacute;n de Conocimientos</div>\r\n      <div class=\"info-box blue\" style=\"margin-bottom:16px\">\r\n        <p>En esta etapa reconocer&aacute; vocabulario t&eacute;cnico y herramientas digitales que le ayudar&aacute;n a comprender mejor el contexto de soporte e instalaci&oacute;n.</p>\r\n      </div>\r\n      <div class=\"card open cat-contexto\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\">&#128269;</div>\r\n            <div>\r\n              <h3>Actividades de Contextualizaci&oacute;n</h3>\r\n              <p>1 actividad &middot; Duraci&oacute;n aproximada: 1 hora</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.2.1</span>\r\n              <span class=\"activity-title\">Reconocimiento de conceptos y herramientas</span>\r\n              <span class=\"mission-chip\">Mision diagnostica</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <p class=\"intro-text\">Esta actividad consta de dos partes para fortalecer el reconocimiento de vocabulario tecnico y la asociacion de herramientas con sus conceptos. Resuelvelas directamente aqui.</p>\r\n\r\n              <div class=\"game-tabs\">\r\n                <button class=\"game-tab active\" type=\"button\" onclick=\"switchTab(this,'tab-sopa-guia5')\">Parte 1 - Sopa de Letras</button>\r\n                <button class=\"game-tab\" type=\"button\" onclick=\"switchTab(this,'tab-relaciona-guia5')\">Parte 2 - Relaciona nombre y concepto</button>\r\n              </div>\r\n\r\n              <div class=\"game-panel\" id=\"tab-sopa-guia5\">\r\n                <div class=\"info-box\" style=\"margin-bottom:12px\">\r\n                  <div class=\"label\">Instrucciones - Sopa de Letras</div>\r\n                  <ul>\r\n                    <li>Identifica terminos asociados con herramientas, protocolos y manuales tecnicos.</li>\r\n                    <li>Relaciona el vocabulario encontrado con el contexto de soporte e instalacion.</li>\r\n                    <li>Comenta con el grupo los conceptos que resulten mas utiles para la guia.</li>\r\n                  </ul>\r\n                </div>\r\n                <div class=\"game-frame-wrap\">\r\n                  <iframe referrerpolicy=\"strict-origin-when-cross-origin\" allow=\"fullscreen; autoplay; allow-top-navigation-by-user-activation\" allowfullscreen width=\"795\" height=\"690\" frameborder=\"0\" src=\"https://es.educaplay.com/juego/27988460-operar_herramientas_informaticas_y_digitales_de_acuerdo_con_protocolos_y_manuales_tecnicos.html\"></iframe>\r\n                </div>\r\n              </div>\r\n\r\n              <div class=\"game-panel\" id=\"tab-relaciona-guia5\" style=\"display:none\">\r\n                <div class=\"info-box green\" style=\"margin-bottom:12px\">\r\n                  <div class=\"label\">Instrucciones - Relaciona nombre y concepto</div>\r\n                  <ul>\r\n                    <li>Lee cada concepto antes de seleccionar la relacion correspondiente.</li>\r\n                    <li>Usa lo trabajado en la sopa de letras como apoyo conceptual.</li>\r\n                    <li>Verifica que cada herramienta quede asociada con su funcion principal.</li>\r\n                  </ul>\r\n                </div>\r\n                <div class=\"game-frame-wrap\">\r\n                  <iframe referrerpolicy=\"strict-origin-when-cross-origin\" allow=\"fullscreen; autoplay; allow-top-navigation-by-user-activation\" allowfullscreen width=\"795\" height=\"690\" frameborder=\"0\" src=\"https://es.educaplay.com/juego/27988974-operar_herramientas_informaticas_y_digitales_de_acuerdo_con_protocolos_y_manuales_tecnicos.html\"></iframe>\r\n                </div>\r\n              </div>\r\n\r\n              <div class=\"info-box\" style=\"margin-top:14px\">\r\n                <div class=\"label\">Datos de la actividad</div>\r\n                <ul>\r\n                  <li>Duracion: 1 hora.</li>\r\n                  <li>Desarrolla primero la sopa de letras y luego la actividad de relacion.</li>\r\n                  <li>Usa los conceptos reconocidos como apoyo para las actividades posteriores de la guia.</li>\r\n                </ul>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"apropiacion\" class=\"section-title\">3.3 &middot; Actividades de Apropiaci&oacute;n</div>\r\n      <div class=\"info-box blue\" style=\"margin-bottom:16px\">\r\n        <p>Aqu&iacute; aplicar&aacute; criterios t&eacute;cnicos para clasificar archivos, consultar requerimientos m&iacute;nimos y registrar informaci&oacute;n de forma organizada.</p>\r\n      </div>\r\n      <div class=\"card open cat-apropiacion\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\">&#128218;</div>\r\n            <div>\r\n              <h3>Actividades de Apropiaci&oacute;n</h3>\r\n              <p>1 actividad &middot; Duraci&oacute;n aproximada: 2 horas</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.3.1</span>\r\n              <span class=\"activity-title\">Clasificacion tecnica de archivos y sistemas</span>\r\n              <span class=\"mission-chip\">Mision tecnica</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <div class=\"warning-box\">\r\n                <strong>Importante</strong>\r\n                <p>Solo se permite el uso e instalacion de herramientas licenciadas o de codigo abierto. Registra la fuente consultada para cada sistema operativo en la matriz.</p>\r\n              </div>\r\n\r\n              <div class=\"subsection-head\" style=\"margin-top:16px;\">\r\n                <h3>Actividad 1: Extensiones de archivo</h3>\r\n                <p>Completa el programa asociado y la descripcion de cada extension.</p>\r\n              </div>\r\n              <div class=\"table-scroll\">\r\n                <table class=\"data-table\">\r\n                  <thead>\r\n                    <tr>\r\n                      <th>Extension</th>\r\n                      <th>Programa / referencia</th>\r\n                      <th>Descripcion o tipo de archivo</th>\r\n                    </tr>\r\n                  </thead>\r\n                  <tbody id=\"extensionTable\"></tbody>\r\n                </table>\r\n              </div>\r\n              <button class=\"btn-export-word\" type=\"button\" onclick=\"openGuide5ExportModal('extensions')\">\r\n                📄 Exportar actividad a Word\r\n              </button>\r\n\r\n              <datalist id=\"programSuggestions\">\r\n                <option value=\"Microsoft Word\"></option>\r\n                <option value=\"Microsoft Excel\"></option>\r\n                <option value=\"Microsoft Access\"></option>\r\n                <option value=\"Microsoft Project\"></option>\r\n                <option value=\"Microsoft PowerPoint\"></option>\r\n                <option value=\"Microsoft Publisher\"></option>\r\n                <option value=\"Adobe Acrobat Reader\"></option>\r\n                <option value=\"WinRAR\"></option>\r\n                <option value=\"VLC Media Player\"></option>\r\n                <option value=\"Windows\"></option>\r\n                <option value=\"Navegador web\"></option>\r\n              </datalist>\r\n\r\n              <div class=\"subsection-head\" style=\"margin-top:20px;\">\r\n                <h3>Actividad 2: Requerimientos minimos de sistemas operativos</h3>\r\n                <p>Investiga procesador, RAM, espacio en disco y la fuente consultada.</p>\r\n              </div>\r\n              <div class=\"table-scroll\">\r\n                <table class=\"data-table\">\r\n                  <thead>\r\n                    <tr>\r\n                      <th>Sistema operativo</th>\r\n                      <th>Procesador</th>\r\n                      <th>RAM</th>\r\n                      <th>Espacio en disco</th>\r\n                      <th>Fuente</th>\r\n                    </tr>\r\n                  </thead>\r\n                  <tbody id=\"systemTable\"></tbody>\r\n                </table>\r\n              </div>\r\n              <button class=\"btn-export-word\" type=\"button\" onclick=\"openGuide5ExportModal('systems')\">\r\n                📄 Exportar actividad a Word\r\n              </button>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"transferencia\" class=\"section-title\">3.4 &middot; Actividades de Transferencia del Conocimiento</div>\r\n      <div class=\"info-box blue\" style=\"margin-bottom:16px\">\r\n        <p>Esta actividad integradora consolida el diagn&oacute;stico, la investigaci&oacute;n y la documentaci&oacute;n t&eacute;cnica en un producto final organizado.</p>\r\n      </div>\r\n      <div class=\"card open cat-transferencia\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\">&#128640;</div>\r\n            <div>\r\n              <h3>Actividades de Transferencia</h3>\r\n              <p>1 actividad integradora &middot; Duraci&oacute;n aproximada: 4 horas</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.4.1</span>\r\n              <span class=\"activity-title\">Guia de instalacion y evidencia tecnica</span>\r\n              <span class=\"mission-chip\">Mision integradora</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <div class=\"subsection-head\">\r\n                <h3>Actividad 1: Guia de instalacion de sistemas operativos</h3>\r\n                <p>Elabora una guia de instalacion paso a paso con capturas de pantalla y evidencias claras de cada fase.</p>\r\n              </div>\r\n\r\n              <div class=\"info-box\" style=\"margin-bottom:16px\">\r\n                <div class=\"label\">Indicaciones esenciales</div>\r\n                <ul class=\"note-list\">\r\n                  <li>Parte A: instala Linux en VirtualBox con la distribucion asignada por tu instructor.</li>\r\n                  <li>Evidencia la tabla de particiones requerida: <code>/home</code>, <code>swap</code>, <code>/boot</code> y <code>/</code>.</li>\r\n                  <li>Parte B: instala Windows en VirtualBox con el sistema operativo designado por tu instructor.</li>\r\n                  <li>Evidencia el manejo de particiones primaria, logica y extendida, segun corresponda.</li>\r\n                  <li>En ambos casos toma capturas de configuracion, particionado, instalacion, primer inicio y verificacion.</li>\r\n                </ul>\r\n              </div>\r\n\r\n              <div class=\"transfer-grid\">\r\n                <article class=\"transfer-card\">\r\n                  <h3>Parte A: Linux en VirtualBox</h3>\r\n                  <p>Usa la distribucion asignada por tu instructor e incluye evidencia del particionado <code>/home</code>, <code>swap</code>, <code>/boot</code> y <code>/</code>.</p>\r\n                  <ul class=\"note-list\">\r\n                    <li>Configure la maquina virtual de acuerdo con la practica asignada.</li>\r\n                    <li>Documente el particionado requerido del sistema Linux.</li>\r\n                    <li>Capture cada fase de la instalacion paso a paso.</li>\r\n                    <li>Verifique y evidencie el primer inicio del sistema.</li>\r\n                  </ul>\r\n                </article>\r\n\r\n                <article class=\"transfer-card\">\r\n                  <h3>Parte B: Windows en VirtualBox</h3>\r\n                  <p>Evidencia el manejo de particiones primaria, logica y extendida segun corresponda para la practica asignada.</p>\r\n                  <ul class=\"note-list\">\r\n                    <li>Configure la maquina virtual para la instalacion de Windows.</li>\r\n                    <li>Documente el manejo de particiones y almacenamiento.</li>\r\n                    <li>Capture la instalacion paso a paso.</li>\r\n                    <li>Verifique el arranque y el funcionamiento del sistema.</li>\r\n                  </ul>\r\n                </article>\r\n              </div>\r\n\r\n              <div class=\"subsection-head\" style=\"margin-top:20px;\">\r\n                <h3>Actividad 2: Desarrollo del taller complementario</h3>\r\n                <p>Realiza las actividades relacionadas en el documento <strong>Taller 1_Guia5</strong> complementarias a la guia de aprendizaje. Al finalizar, adjunta los resultados al documento de evidencia.</p>\r\n              </div>\r\n\r\n              <div class=\"info-box\" style=\"margin-top:16px\">\r\n                <div class=\"label\">Instalador base para la practica</div>\r\n                <p>Abre el instalador de VirtualBox antes de iniciar la evidencia tecnica y usalo como apoyo para crear las maquinas virtuales de Linux y Windows.</p>\r\n                <div class=\"drive-action-group\">\r\n                  <a class=\"btn-drive\" href=\"https://drive.google.com/drive/folders/19AY6LsSHM--2VVXp4_Bzzjz2SVyAiSMc?usp=sharing\" target=\"_blank\" rel=\"noopener noreferrer\">💻 Abrir instalador de VirtualBox en Drive ↗</a>\r\n                </div>\r\n              </div>\r\n\r\n              <div class=\"subsection-head\" style=\"margin-top:20px;\">\r\n                <h3>Informe tecnico (Documento bajo normas IEEE)</h3>\r\n                <p>Elabora un informe tecnico bajo normas IEEE que incluya todo el desarrollo del taller, es decir, las Actividades 1 y 2, con sus respectivas evidencias: capturas, tablas y respuestas.</p>\r\n              </div>\r\n\r\n              <div class=\"panel-grid panel-grid-single\" style=\"margin-top:16px;\">\r\n                <article class=\"checklist-card\">\r\n                  <h3>Informe tecnico bajo normas IEEE</h3>\r\n                  <p>El informe final debe integrar el desarrollo de las Actividades 1 y 2 con sus respectivas evidencias: capturas, tablas, respuestas y conclusiones.</p>\r\n                  <h4>Antes de enviar</h4>\r\n                  <ul class=\"note-list\">\r\n                    <li>Verifica que respondiste todos los puntos solicitados.</li>\r\n                    <li>Incluye capturas de pantalla claras y bien organizadas.</li>\r\n                    <li>Cuida la ortografia y la redaccion tecnica del documento.</li>\r\n                    <li>Revisa que el formato IEEE este completo.</li>\r\n                    <li>Usa el nombre de archivo <code>Guia5_Taller1_NombreAprendiz.doc</code>.</li>\r\n                    <li>Entrega el archivo final en el enlace dispuesto por tu instructor.</li>\r\n                  </ul>\r\n                  <div class=\"info-box\" style=\"margin-top:16px\">\r\n                    <div class=\"label\">Nota importante</div>\r\n                    <p>La estructura minima del documento debe incluir los siguientes apartados:</p>\r\n                    <ul class=\"note-list\">\r\n                      <li>Abstract (resumen en ingles).</li>\r\n                      <li>Keywords (palabras clave).</li>\r\n                      <li>Introduccion: explica de que trata el documento.</li>\r\n                      <li>Contenido: desarrollo de las actividades planteadas.</li>\r\n                      <li>Conclusiones: explica que aprendiste en la practica.</li>\r\n                      <li>Bibliografia presentada bajo normas IEEE.</li>\r\n                    </ul>\r\n                  </div>\r\n                </article>\r\n\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"evidencias\" class=\"section-title\">Planteamiento de Evidencias de Aprendizaje</div>\r\n      <div class=\"card open cat-evaluacion\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\">&#128202;</div>\r\n            <div>\r\n              <h3>Evidencias y Criterios de Evaluaci&oacute;n</h3>\r\n              <p>Resumen de lo que debe entregar y c&oacute;mo ser&aacute; evaluado</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"table-scroll\">\r\n            <table class=\"data-table\">\r\n              <thead>\r\n                <tr>\r\n                  <th>Fase del proyecto</th>\r\n                  <th>Actividad del proyecto</th>\r\n                  <th>Actividad de aprendizaje</th>\r\n                  <th>Evidencias</th>\r\n                  <th>Criterios de evaluacion</th>\r\n                  <th>Tecnicas e instrumentos</th>\r\n                </tr>\r\n              </thead>\r\n              <tbody id=\"evidenceTable\"></tbody>\r\n            </table>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"glosario\" class=\"section-title\">Glosario de T&eacute;rminos</div>\r\n      <div class=\"card open cat-glosario\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\">&#128214;</div>\r\n            <div>\r\n              <h3>Glosario de T&eacute;rminos</h3>\r\n              <p>Definiciones clave para comprender la gu&iacute;a y sus actividades</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <label class=\"search-box\">\r\n            <span>Buscar termino</span>\r\n            <input type=\"search\" id=\"glossarySearch\" placeholder=\"Ejemplo: BIOS, backup, particion, hipervisor\">\r\n          </label>\r\n          <div class=\"glossary-grid\" id=\"glossaryGrid\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"referencias\" class=\"section-title\">Referentes Bibliogr&aacute;ficos</div>\r\n      <div class=\"card open\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\" style=\"background:#ede7f6\">&#128279;</div>\r\n            <div>\r\n              <h3>Referencias Bibliogr&aacute;ficas</h3>\r\n              <p>Fuentes consultadas para orientar esta gu&iacute;a y sus actividades</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <ol class=\"reference-list\">\r\n            <li>Servicio Nacional de Aprendizaje (SENA). Guia de aprendizaje - Formato GFPI-F-135.</li>\r\n            <li>Oracle. Oracle VM VirtualBox User Manual.</li>\r\n            <li>VMware. Workstation / Player Documentation.</li>\r\n            <li>Microsoft. Documentacion oficial de instalacion y soporte de Windows 10 y Windows 11.</li>\r\n            <li>Canonical Ltd. Ubuntu Documentation.</li>\r\n            <li>Linux Foundation. Filesystem Hierarchy Standard.</li>\r\n            <li>IEEE. IEEE Editorial Style Manual / IEEE Style Guide.</li>\r\n            <li>NIST. Computer Security Resource Center.</li>\r\n            <li>Google. Centro de ayuda de Google Drive.</li>\r\n            <li>Microsoft. Centro de ayuda de Microsoft Teams y SharePoint.</li>\r\n          </ol>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"material-apoyo\" class=\"section-title\">Material de Apoyo</div>\r\n      <div class=\"card open\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\" style=\"background:#e8f0fe\">&#128194;</div>\r\n            <div>\r\n              <h3>Material de Apoyo y Recursos</h3>\r\n              <p>Recursos visuales y orientaciones para acompa&ntilde;ar el desarrollo de la gu&iacute;a</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"info-box\">\r\n            <div class=\"label\">Ruta local del material</div>\r\n            <p>\r\n              Este material se abre desde la ruta\r\n              <code class=\"support-path\">assets/materiales/guia5</code>.\r\n            </p>\r\n          </div>\r\n\r\n          <div class=\"material-heading\">Plantillas de trabajo</div>\r\n          <div class=\"resource-grid\" id=\"supportTemplatesGrid\"></div>\r\n\r\n          <div class=\"material-heading\">Documentos y guias de consulta</div>\r\n          <div class=\"resource-grid\" id=\"supportDocsGrid\"></div>\r\n\r\n          <div class=\"material-heading\">Herramientas y software</div>\r\n          <div class=\"resource-grid\" id=\"supportToolsGrid\"></div>\r\n\r\n          <div class=\"panel-grid\" style=\"margin-top:16px;\">\r\n            <div class=\"support-card\">\r\n              <img src=\"assets/img/no-bootable-device.jpeg\" alt=\"Error no bootable device\">\r\n              <p>Referencia visual 1: mensaje clasico cuando el equipo no encuentra un medio valido de arranque.</p>\r\n            </div>\r\n            <div class=\"support-card\">\r\n              <img src=\"assets/img/sopa-letras.png\" alt=\"Sopa de letras\">\r\n              <p>Referencia visual 2: material de apoyo para la actividad de contextualizacion y vocabulario tecnico.</p>\r\n            </div>\r\n            <div class=\"notes-card\">\r\n              <h3>Sugerencias de uso</h3>\r\n              <ul class=\"note-list\">\r\n                <li>Usa la bitacora y el taller como base para estructurar tus entregas.</li>\r\n                <li>Consulta VirtualBox y Linux Boot Process antes de la practica de instalacion.</li>\r\n                <li>Apoya el informe final con los documentos de normas IEEE y ciberseguridad.</li>\r\n                <li>Guarda evidencias con nombres claros dentro de tu portafolio de aprendizaje.</li>\r\n              </ul>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </main>\r\n</div>\r\n\r\n<div class=\"modal-overlay\" id=\"guide5-export-modal\" onclick=\"if(event.target===this)closeGuide5ExportModal()\">\r\n  <div class=\"modal-box\">\r\n    <h3 id=\"guide5-export-title\">📄 Exportar actividad a Word</h3>\r\n    <p id=\"guide5-export-description\">Ingresa tu nombre completo para guardar el documento.</p>\r\n\r\n    <div class=\"modal-ficha-warn\" id=\"guide5-export-warn\" style=\"display:none\">\r\n      ⚠️ <strong>No has seleccionado tu ficha.</strong><br>\r\n      Regresa a <a href=\"index.html\">la página de inicio</a> y elige tu institución y grupo antes de exportar.\r\n    </div>\r\n\r\n    <div class=\"modal-ficha-ok\" id=\"guide5-export-ok\" style=\"display:none\">\r\n      <div class=\"mf-label\">📎 El archivo se guardará como:</div>\r\n      <div class=\"mf-file\" id=\"guide5-export-filename\">Nombre_Ficha.doc</div>\r\n    </div>\r\n\r\n    <input\r\n      id=\"guide5-export-name\"\r\n      type=\"text\"\r\n      placeholder=\"Nombre y apellidos del aprendiz\"\r\n      maxlength=\"80\"\r\n      oninput=\"updateGuide5ExportFilenamePreview()\"\r\n      onkeydown=\"if(event.key==='Enter')doGuide5ExportWord()\"\r\n    >\r\n    <div class=\"modal-error-msg\" id=\"guide5-export-error\">Por favor ingresa tu nombre antes de continuar.</div>\r\n\r\n    <div class=\"modal-actions\">\r\n      <button class=\"modal-btn-cancel\" type=\"button\" onclick=\"closeGuide5ExportModal()\">Cancelar</button>\r\n      <button class=\"modal-btn-ok\" type=\"button\" id=\"guide5-export-ok-btn\" onclick=\"doGuide5ExportWord()\">⬇ Descargar Word</button>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<script>\r\n(function () {\r\n  var grupo = String((document.body && document.body.dataset && document.body.dataset.defaultGrupo) || \"11A\").toUpperCase();\r\n  var config = {\r\n    \"11A\": {\r\n      currentFile: \"grupo-11a-guia-05-herramientas-informaticas-digitales.html\",\r\n      currentLabel: \"Operar herramientas informaticas y digitales | 11A\",\r\n      campus: \"Santa Barbara | 11A\"\r\n    },\r\n    \"11B\": {\r\n      currentFile: \"grupo-11b-guia-05-herramientas-informaticas-digitales.html\",\r\n      currentLabel: \"Operar herramientas informaticas y digitales | 11B\",\r\n      campus: \"Santa Barbara | 11B\"\r\n    }\r\n  }[grupo] || null;\r\n\r\n  if (!config) {\r\n    return;\r\n  }\r\n\r\n  var currentGuideNavLink = document.getElementById(\"currentGuideNavLink\");\r\n  var currentGuideNavLabel = document.getElementById(\"currentGuideNavLabel\");\r\n  var topbarCampus = document.getElementById(\"topbarCampus\");\r\n\r\n  if (currentGuideNavLink) {\r\n    currentGuideNavLink.href = config.currentFile;\r\n    currentGuideNavLink.dataset.currentFile = config.currentFile;\r\n  }\r\n  if (currentGuideNavLabel) {\r\n    currentGuideNavLabel.textContent = config.currentLabel;\r\n  }\r\n  if (topbarCampus) {\r\n    topbarCampus.textContent = config.campus;\r\n  }\r\n})();\r\n</script>\r\n";
